import requests
import os


class Tools:
    @staticmethod
    def run(query: str, model: str = "grok-3") -> dict:
        """
        Send research/reasoning query to xAI Grok API.
        Good for math, code, obscure references, step-by-step thinking.
        """
        api_key = os.environ.get("XAI_API_KEY")
        if not api_key:
            return {"error": "XAI_API_KEY not found"}

        url = "https://api.x.ai/v1/chat/completions"

        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        }

        payload = {
            "model": model,
            "messages": [
                {
                    "role": "system",
                    "content": "You are Grok, an expert academic and reasoning assistant built by xAI. Provide detailed, accurate, step-by-step answers.",
                },
                {"role": "user", "content": query},
            ],
            "temperature": 0.4,
            "max_tokens": 4096,
        }

        try:
            r = requests.post(url, headers=headers, json=payload, timeout=90)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
